const input = $json;

function normalizeUrl(raw) {
  const value = String(raw ?? '').trim();

  if (!value) {
    return {
      normalized: null,
      host: null,
      pathname: null,
      error_code: 'INVALID_SOURCE_URL',
      error_message: 'Source URL is empty'
    };
  }

  let working = value;

  if (!/^https?:\/\//i.test(working)) {
    working = 'https://' + working;
  }

  const match = working.match(/^(https?):\/\/([^\/?#]+)(\/[^?#]*)?/i);

  if (!match) {
    return {
      normalized: null,
      host: null,
      pathname: null,
      error_code: 'INVALID_SOURCE_URL',
      error_message: 'Source URL format is invalid'
    };
  }

  const protocol = match[1].toLowerCase();
  const host = match[2].toLowerCase().replace(/\.$/, '');
  const pathname = match[3] || '/';

  const normalized = `${protocol}://${host}${pathname}`;

  return {
    normalized,
    host,
    pathname,
    error_code: null,
    error_message: null
  };
}

const rawUrl = input.source_url || input.url || null;
const result = normalizeUrl(rawUrl);

return {
  json: {
    ...input,
    source_id: input.source_id || input.id || null,
    source_name: input.source_name || input.name || null,
    source_url_original: rawUrl,
    source_url_normalized: result.normalized,
    fetch_url: result.normalized,
    host: result.host,
    pathname: result.pathname,
    fetch_status: result.normalized ? 'PENDING' : 'INVALID_SOURCE_URL',
    profile_status: 'PENDING',
    parse_status: 'PENDING',
    validation_status: 'PENDING',
    error_code: result.error_code,
    error_message: result.error_message
  }
};

const items = $input.all();

const blockedFragments = [
  '/impressum',
  '/datenschutz',
  '/privacy',
  '/kontakt',
  '/contact',
  '/login',
  '/signin',
  '/spende',
  '/donation'
];

return items.filter((item) => {
  const j = item.json || {};
  const normalizedUrl =
    typeof j.source_url_normalized === 'string' ? j.source_url_normalized : null;

  if (!normalizedUrl) return false;

  const lower = normalizedUrl.toLowerCase();

  if (blockedFragments.some((fragment) => lower.includes(fragment))) {
    return false;
  }

  return true;
});

function classifyFetch(item) {
  const statusCode = Number(item.statusCode ?? item.status_code ?? 0);
  const body = typeof item.body === 'string'
    ? item.body
    : typeof item.data === 'string'
      ? item.data
      : item.data && typeof item.data.body === 'string'
        ? item.data.body
        : null;
  const rawError = item.error ? String(item.error.message || item.error || '') : '';
  const finalUrl = typeof item.url === 'string'
    ? item.url
    : typeof item.final_url === 'string'
      ? item.final_url
      : item.source_url_normalized;

  if (item.fetch_status === 'INVALID_SOURCE_URL') {
    return { fetch_status: 'INVALID_SOURCE_URL', error_code: 'INVALID_SOURCE_URL', error_message: item.error_message || 'Invalid source URL', body, statusCode, finalUrl };
  }
  if (/ENOTFOUND/i.test(rawError)) {
    return { fetch_status: 'DNS_ERROR', error_code: 'DNS_ERROR', error_message: rawError, body, statusCode, finalUrl };
  }
  if (/EPROTO|SSL|TLS/i.test(rawError)) {
    return { fetch_status: 'TLS_ERROR', error_code: 'TLS_ERROR', error_message: rawError, body, statusCode, finalUrl };
  }
  if (/timeout/i.test(rawError)) {
    return { fetch_status: 'FETCH_TIMEOUT', error_code: 'FETCH_TIMEOUT', error_message: rawError, body, statusCode, finalUrl };
  }
  if (rawError) {
    return { fetch_status: 'UNKNOWN_ERROR', error_code: 'UNKNOWN_ERROR', error_message: rawError, body, statusCode, finalUrl };
  }
  if (statusCode >= 400) {
    return { fetch_status: 'HTTP_ERROR', error_code: 'HTTP_ERROR', error_message: `HTTP ${statusCode}`, body, statusCode, finalUrl };
  }
  if (typeof body !== 'string' || body.trim().length < 80) {
    return { fetch_status: 'EMPTY_RESPONSE', error_code: 'EMPTY_RESPONSE', error_message: 'Response body missing or too short', body, statusCode, finalUrl };
  }
  if (/captcha|access denied|forbidden|enable cookies|anmelden|einloggen|login/i.test(body)) {
    return { fetch_status: 'BLOCKED', error_code: 'BLOCKED', error_message: 'Blocked or login wall', body, statusCode, finalUrl };
  }
  return { fetch_status: 'SUCCESS', error_code: null, error_message: null, body, statusCode, finalUrl };
}

const result = classifyFetch($json);
return {
  json: {
    ...$json,
    fetch_status: result.fetch_status,
    profile_status: result.fetch_status === 'SUCCESS' ? 'READY' : 'FETCH_ERROR',
    error_code: result.error_code,
    error_message: result.error_message,
    status_code: result.statusCode || null,
    final_url: result.finalUrl || $json.source_url_normalized || null,
    html: result.body,
  }
};

const html = typeof $json.data === 'string' ? $json.data : '';
const baseUrl = $json.url || $json.source_url_original || null;

const navigationLinks = [];
const seen = new Set();
let hrefMatchCount = 0;
const hrefSamples = [];

function addSample(value) {
  if (!value) return;
  if (hrefSamples.length >= 10) return;
  hrefSamples.push(String(value));
}

function parseAbsolute(url) {
  const match = String(url || '').match(/^(https?):\/\/([^\/?#]+)(\/[^?#]*)?(\?[^#]*)?/i);
  if (!match) return null;
  return {
    protocol: match[1].toLowerCase(),
    host: match[2].toLowerCase().replace(/\.$/, ''),
    path: match[3] || '/',
    query: match[4] || ''
  };
}

function normalizePath(path) {
  const value = String(path || '/').replace(/\/+/g, '/');
  return value.startsWith('/') ? value : `/${value}`;
}

function resolveUrl(rawHref, rawBaseUrl) {
  const href = String(rawHref || '').trim();
  const base = parseAbsolute(rawBaseUrl);
  if (!href || !base) return null;

  if (/^https?:\/\//i.test(href)) {
    const absolute = parseAbsolute(href);
    return absolute
      ? `${absolute.protocol}://${absolute.host}${normalizePath(absolute.path)}${absolute.query}`
      : null;
  }

  if (/^\/\//.test(href)) {
    return `${base.protocol}:${href}`;
  }

  if (href.startsWith('/')) {
    return `${base.protocol}://${base.host}${normalizePath(href)}`;
  }

  const baseDir = (() => {
    const path = normalizePath(base.path);
    if (path === '/') return '/';
    return path.replace(/\/[^/]*$/, '/');
  })();

  return `${base.protocol}://${base.host}${normalizePath(baseDir + href)}`;
}

function addLink(rawHref) {
  if (!rawHref) return;
  const href = String(rawHref).trim();
  if (!href) return;
  addSample(href);
  if (href.startsWith('#')) return;
  if (/^(mailto:|tel:|javascript:)/i.test(href)) return;

  const normalized = resolveUrl(href, baseUrl);
  if (!normalized) return;

  if (seen.has(normalized)) return;
  seen.add(normalized);
  navigationLinks.push(normalized);
}

try {
  if (html && baseUrl) {
    const hrefRegex = /href\s*=\s*["']([^"']+)["']/gi;

    let match;
    while ((match = hrefRegex.exec(html)) !== null) {
      hrefMatchCount += 1;
      addLink(match[1]);
      if (navigationLinks.length >= 50) break;
    }
  }
} catch (error) {
  // niemals crashen
}

return {
  json: {
    ...$json,
    profile_status: 'PROFILED',
    navigation_links: navigationLinks,
    debug_href_match_count: hrefMatchCount,
    debug_href_samples: hrefSamples,
    debug_navigation_link_count: navigationLinks.length
  }
};

const POSITIVE = [
  'veranstaltung','veranstaltungen','event','events',
  'termin','termine','kalender','programm','agenda',
  'seminar','workshop','konferenz','kultur','festival'
];

const NEGATIVE = [
  'impressum','datenschutz','privacy','kontakt','contact',
  'login','signin','spende','donation','mailto','tel'
];

const links = Array.isArray($json.navigation_links)
  ? $json.navigation_links
  : [];

const seen = new Set();
const candidates = [];

for (const link of links) {
  if (!link || typeof link !== 'string') continue;

  const lower = link.toLowerCase();

  if (NEGATIVE.some(n => lower.includes(n))) continue;

  const positiveHits = POSITIVE.filter(p => lower.includes(p));

  if (positiveHits.length === 0) continue;

  if (seen.has(link)) continue;
  seen.add(link);

  candidates.push({
    candidate_url: link,
    candidate_label: null,
    candidate_reasons: positiveHits,
    candidate_negative_tokens: []
  });

  if (candidates.length >= 20) break;
}

return {
  json: {
    ...$json,
    candidates
  }
};

const positivesRaw = Array.isArray($json.candidate_reason_tokens)
  ? $json.candidate_reason_tokens
  : [];

const negativesRaw = Array.isArray($json.candidate_negative_tokens)
  ? $json.candidate_negative_tokens
  : [];

const positives = [...new Set(positivesRaw)];
const negatives = [...new Set(negativesRaw)];

function getHostname(rawUrl) {
  const value = String(rawUrl || '').trim();
  const match = value.match(/^https?:\/\/([^\/?#]+)/i);
  return match
    ? match[1].toLowerCase().replace(/^www\./i, '').replace(/\.$/, '')
    : null;
}

function getPath(rawUrl) {
  const value = String(rawUrl || '').trim();
  const match = value.match(/^https?:\/\/[^\/?#]+(\/[^?#]*)?/i);
  return match ? (match[1] || '/') : '/';
}

const seedHost = getHostname($json.seed_source_url);
const candidateHost = getHostname($json.candidate_url);

const sameDomain = Boolean(
  seedHost &&
  candidateHost &&
  seedHost === candidateHost
);

const hasCandidateUrl =
  typeof $json.candidate_url === 'string' &&
  $json.candidate_url.trim().length > 0;

const candidatePath = getPath($json.candidate_url).toLowerCase();

const eventPathHints = [
  '/veranstaltung',
  '/veranstaltungen',
  '/event',
  '/events',
  '/kalender',
  '/programm',
  '/termine'
];

const genericPathHints = [
  '/news',
  '/presse',
  '/kontakt',
  '/impressum',
  '/datenschutz'
];

const hasEventPathHint = eventPathHints.some((hint) =>
  candidatePath.includes(hint)
);

const hasGenericPathHint = genericPathHints.some((hint) =>
  candidatePath.includes(hint)
);

const pathDepth = candidatePath.split('/').filter(Boolean).length;
const hasDeeperPath = pathDepth >= 2;

let score =
  18 +
  positives.length * 7 -
  negatives.length * 12 +
  (sameDomain ? 12 : 0) +
  (hasCandidateUrl ? 4 : 0) +
  (hasEventPathHint ? 6 : 0) +
  (hasDeeperPath ? 4 : 0) -
  (hasGenericPathHint ? 6 : 0);

score = Math.max(10, Math.min(60, score));

return {
  json: {
    ...$json,
    discovery_confidence: score,
    collector_ready: false,
    review_required: true,
    insertable: hasCandidateUrl && score >= 24,
    discovery_notes:
      `DISCOVERY_REVIEW_REQUIRED; ` +
      `seed=${$json.source_name || 'unknown'}; ` +
      `positives=${positives.join(',') || 'none'}; ` +
      `negatives=${negatives.join(',') || 'none'}; ` +
      `same_domain=${sameDomain ? 'yes' : 'no'}; ` +
      `event_path=${hasEventPathHint ? 'yes' : 'no'}; ` +
      `generic_path=${hasGenericPathHint ? 'yes' : 'no'}; ` +
      `path_depth=${pathDepth}`
  }
};

const items = $input.all();
const out = [];

for (const item of items) {
  const j = item.json || {};
  const candidates = Array.isArray(j.candidates) ? j.candidates : [];

  for (const candidate of candidates) {
    if (!candidate || !candidate.candidate_url) continue;

    out.push({
      json: {
        run_id: j.run_id || null,
        source_id: j.source_id || null,
        source_name: j.source_name || null,
        platform: j.platform || null,
        source_kind: j.source_kind || null,
        trust_score: j.trust_score ?? null,
        discovery_method: j.discovery_method || null,
        seed_source_url: j.source_url_original || j.url || null,
        source_url_original: j.source_url_original || j.url || null,
        source_url_normalized: j.source_url_normalized || null,
        profile_status: j.profile_status || null,
        fetch_status: j.fetch_status || null,
        candidate_url: candidate.candidate_url,
        candidate_label: candidate.candidate_label || null,
        candidate_reason_tokens: Array.isArray(candidate.candidate_reasons)
          ? candidate.candidate_reasons
          : [],
        candidate_reasons: Array.isArray(candidate.candidate_reasons)
          ? candidate.candidate_reasons
          : [],
        candidate_negative_tokens: Array.isArray(candidate.candidate_negative_tokens)
          ? candidate.candidate_negative_tokens
          : []
      }
    });
  }
}

return out;

const safeItems = (nodeName) => {
  try {
    const value = $items(nodeName);
    return Array.isArray(value) ? value : [];
  } catch (error) {
    return [];
  }
};

const runId =
  safeItems('Pass Discovery Run Context')[0]?.json?.run_id ??
  $input.first()?.json?.run_id ??
  null;

const loadSeedItems = safeItems('Load Seed Sources');
const normalizeFetchItems = safeItems('Normalize Seed Fetch Result');
const extractCandidateItems = safeItems('Extract Discovery Candidates');
const insertedItems = safeItems('Insert Discovered Sources');

const sourcesTotal = loadSeedItems.length;
const sourcesFetchedOk = normalizeFetchItems.filter(
  item => item?.json?.fetch_status === 'SUCCESS'
).length;
const sourcesFailed = normalizeFetchItems.filter(
  item => item?.json?.fetch_status && item?.json?.fetch_status !== 'SUCCESS'
).length;

const candidatesTotal = extractCandidateItems.length;
const candidatesInserted = insertedItems.length;

const log = {
  sources_total: sourcesTotal,
  sources_fetched_ok: sourcesFetchedOk,
  sources_failed: sourcesFailed,
  candidates_total: candidatesTotal,
  candidates_inserted: candidatesInserted
};

return [
  {
    json: {
      run_id: runId,
      items_found: candidatesTotal,
      items_created: candidatesInserted,
      items_failed: sourcesFailed,
      sources_total: sourcesTotal,
      sources_fetched_ok: sourcesFetchedOk,
      sources_failed: sourcesFailed,
      candidates_total: candidatesTotal,
      candidates_inserted: candidatesInserted,
      log_text: JSON.stringify(log)
    }
  }
];
